INSERT INTO `episode_overrides` (`id`, `anime_id`, `episode_num`, `image_url`, `synopsis`, `watch_links`, `updated_by`, `updated_at`) VALUES
('5', '61316', '1', 'https://static0.cbrimages.com/wordpress/wp-content/uploads/2026/03/re-zero-season-4-op-with-emilia-smiling.jpg?q=70&fit=crop&w=1328&h=747&dpr=1', 'Faced with the problems caused by the witch''s cult in Priestella, Anastasia makes a voracious suggestion to the main group. Garfiel remains in Priestella and revisits his amnesiac mother.', '[{"service":"crunchyroll","url":"https:\/\/www.crunchyroll.com\/series\/GRGG9798R\/rezero--starting-life-in-another-world-"},{"service":"youtube","url":"https:\/\/www.youtube.com\/channel\/UCGbshtvS9t-8CW11W7TooQg"}]', '2', '2026-05-10 12:23:15'),
  ('7', '61316', '2', 'https://otakukart.com/wp-content/uploads/2026/04/ReZero-Season-4-Episode-2-1536x864.jpg', 'The episode began with everyone finally ready to set out on the journey. The problem, as we already know, was that it was going to be difficult. You simply cannot get closer to the tower. However, Subaru and Emilia received information from a kind tavern owner that birds can be seen heading towards the tower, and, conveniently, Ram can see visions of other animals.', '[{"service":"crunchyroll","url":"https:\/\/www.crunchyroll.com\/series\/GRGG9798R\/rezero--starting-life-in-another-world-"},{"service":"youtube","url":"https:\/\/www.youtube.com\/channel\/UCGbshtvS9t-8CW11W7TooQg"}]', '2', '2026-05-10 12:28:31'),
  ('9', '61316', '3', 'https://fwmedia.fandomwire.com/wp-content/uploads/2026/04/22114407/subaru-using-invisible-providence-re-zero.png?width=800&height=500&quality=85&sharpen=true&format=webp&aspect_ratio=800%3A500&crop=center', 'The episode begins with Subaru waking up near Ram, Patrasche, and Anastasia after being separated from the rest of the group due to a spatial distortion caused in the previous episode. As they move forward, the group encounters dizziness and mental strain, symptoms of the Witch’s miasma, a dark magical force that erodes both mind and body when too dense. This miasma gradually amplifies irritability and aggression, setting the stage for Subaru’s breakdown.', '[{"service":"crunchyroll","url":"https:\/\/www.crunchyroll.com\/series\/GRGG9798R\/rezero--starting-life-in-another-world-"},{"service":"youtube","url":"https:\/\/www.youtube.com\/channel\/UCGbshtvS9t-8CW11W7TooQg"}]', '2', '2026-05-10 12:33:04'),
  ('10', '61316', '4', 'https://static0.gamerantimages.com/wordpress/wp-content/uploads/2026/04/rezero-season-4-episode-4-shaula-hugging-subaru.jpg?q=49&fit=crop&w=825&dpr=2', 'Subaru and the group finally reach the mysterious Pleiades Watchtower after surviving the deadly Auguria Dunes. Subaru wakes from a disturbing nightmare and is cared for by Emilia before the party encounters Shaula — the eccentric guardian of the tower.', '[{"service":"crunchyroll","url":"https:\/\/www.crunchyroll.com\/series\/GRGG9798R\/rezero--starting-life-in-another-world-"},{"service":"youtube","url":"https:\/\/www.youtube.com\/channel\/UCGbshtvS9t-8CW11W7TooQg"}]', '2', '2026-05-10 12:36:44'),
  ('11', '61316', '5', 'https://static0.gamerantimages.com/wordpress/wp-content/uploads/2026/05/rezero-season-4-episode-5-review-typhon-witch-of-pride.jpg?q=49&fit=crop&w=825&dpr=2', 'Subaru and the others clear the constellation-based trial, which transforms the tower’s third floor into an enormous library filled with the “Books of the Dead.”
INSERT INTO `favorites` (`id`, `user_id`, `anime_id`, `anime_title`, `anime_image`, `created_at`) VALUES
('6', '2', '53802', '2.5 Dimensional Seduction', 'https://anivault.unaux.com/assets/img/anime-library/anime-53802.jpg', '2026-05-29 08:59:38'),
