('101', '12', '2', 'yeah they hacked my microsoft account too and i think they found the password in my browsers saved password, but i changed my password and 2fa just after first time but still they hacked me again and again...', '2026-05-15 13:47:52', '100'),
  ('102', '12', '2', 'ah sound bad, bro it might be a rat virus i think.. u should clear and check ur pc..', '2026-05-15 13:48:09', '98'),
  ('103', '12', '2', '.', '2026-05-15 13:48:31', '88'),
  ('104', '13', '2', 'hi', '2026-05-15 19:02:38', NULL),
